1	/* ============================================================
2	   components.css — Reusable UI (nav, buttons, tags, panels, chips)
3	   ============================================================ */
4	
5	/* ---------- Top Nav ---------- */
6	.nav {
7	  position: sticky; top: 0; z-index: 40;
8	  background: var(--nav-bg);
9	  backdrop-filter: saturate(180%) blur(10px);
10	  border-bottom: 1px solid var(--line);
11	}
12	.nav-inner {
13	  max-width: 1280px; margin: 0 auto;
14	  display: flex; align-items: center; justify-content: space-between;
15	  padding: 14px 24px;
16	}
17	.brand {
18	  display: flex; align-items: center; gap: 10px;
19	  font-weight: 800; letter-spacing: -0.01em;
20	  color: var(--ink);
21	}
22	.brand-mark {
23	  width: 32px; height: 32px; border-radius: 8px;
24	  background: linear-gradient(135deg, var(--sap-blue) 0%, var(--sap-cyan) 100%);
25	  display: grid; place-items: center;
26	  color: white; font-weight: 800; font-size: 14px;
27	  box-shadow: 0 4px 10px rgba(0,112,242,.35);
28	}
29	.brand-text { font-size: 16px; }
30	.brand-text b { color: var(--sap-blue); }
31	
32	.nav-links { display: flex; gap: 22px; align-items: center; }
33	.nav-links a { color: var(--ink-2); font-weight: 500; font-size: 14px; }
34	.nav-links a:hover { color: var(--sap-blue); text-decoration: none; }
35	
36	.nav-sap-logo {
37	  display: inline-flex; align-items: center;
38	  padding: 6px 14px; border-radius: 10px;
39	  background: var(--white); border: 1px solid var(--line);
40	  box-shadow: var(--shadow-sm);
41	  transition: transform .15s ease, box-shadow .15s ease;
42	}
43	.nav-sap-logo:hover {
44	  transform: translateY(-1px);
45	  box-shadow: var(--shadow-md);
46	  text-decoration: none;
47	}
48	.nav-sap-logo img { height: 22px; width: auto; display: block; }
49	
50	/* Theme toggle (nav) — sun ↔ moon icon swap via data-theme */
51	.theme-toggle {
52	  display: inline-flex; align-items: center; justify-content: center;
53	  width: 38px; height: 38px;
54	  border-radius: 999px;
55	  background: var(--white);
56	  border: 1px solid var(--line);
57	  color: var(--ink-2);
58	  cursor: pointer;
59	  position: relative;
60	  transition: transform .15s ease, box-shadow .15s ease, border-color .15s ease, background-color .3s ease, color .3s ease;
61	  box-shadow: var(--shadow-sm);
62	}
63	.theme-toggle:hover {
64	  transform: translateY(-1px);
65	  box-shadow: var(--shadow-md);
66	  border-color: var(--sap-blue);
67	  color: var(--sap-blue);
68	}
69	.theme-toggle svg {
70	  width: 18px; height: 18px;
71	  position: absolute;
72	  transition: transform .35s cubic-bezier(.4,0,.2,1), opacity .25s ease;
73	}
74	/* Light theme → show sun, hide moon (rotated off) */
75	.theme-toggle .tt-sun  { transform: rotate(0deg)  scale(1);   opacity: 1; }
76	.theme-toggle .tt-moon { transform: rotate(-90deg) scale(0);  opacity: 0; }
77	/* Dark theme → show moon, hide sun */
78	[data-theme="dark"] .theme-toggle .tt-sun  { transform: rotate(90deg)  scale(0); opacity: 0; }
79	[data-theme="dark"] .theme-toggle .tt-moon { transform: rotate(0deg)   scale(1); opacity: 1; }
80	
81	/* Mobile hamburger (Phase B addition) */
82	.nav-toggle {
83	  display: none;
84	  background: transparent; border: 1px solid var(--line);
85	  border-radius: 10px; padding: 8px 10px; cursor: pointer;
86	  color: var(--ink);
87	}
88	.nav-toggle svg { display: block; }
89	
90	@media (max-width: 720px) {
91	  .nav-links {
92	    position: absolute; top: 60px; right: 16px; left: 16px;
93	    background: rgba(255,255,255,.98);
94	    border: 1px solid var(--line); border-radius: var(--radius-md);
95	    padding: 14px; flex-direction: column; align-items: stretch; gap: 10px;
96	    box-shadow: var(--shadow-md);
97	    display: none;
98	  }
99	  .nav-links.open { display: flex; }
100	  .nav-links a { font-size: 15px; padding: 8px 6px; }
101	  .nav-toggle { display: inline-flex; }
102	}
103	
104	/* ---------- Buttons ---------- */
105	.btn {
106	  display: inline-flex; align-items: center; gap: 8px;
107	  padding: 10px 18px; border-radius: 999px;
108	  font-weight: 600; font-size: 14px;
109	  transition: transform .15s ease, box-shadow .15s ease;
110	}
111	.btn-primary {
112	  background: var(--btn-primary-bg); color: var(--btn-primary-text);
113	  box-shadow: 0 4px 14px rgba(11,27,51,.18);
114	}
115	.btn-primary:hover { transform: translateY(-1px); box-shadow: 0 8px 22px rgba(11,27,51,.25); text-decoration: none; }
116	.btn-yellow {
117	  background: var(--sap-yellow); color: #0B1B33;
118	  box-shadow: 0 4px 14px rgba(255,199,0,.35);
119	}
120	.btn-yellow:hover { transform: translateY(-1px); box-shadow: 0 8px 22px rgba(255,199,0,.45); text-decoration: none; }
121	
122	/* ---------- Tags ---------- */
123	.tag {
124	  display: inline-flex; align-items: center; gap: 6px;
125	  padding: 6px 12px; border-radius: 999px;
126	  background: var(--white); border: 1px solid var(--line);
127	  font-size: 13px; color: var(--ink-2); font-weight: 500;
128	  box-shadow: var(--shadow-sm);
129	}
130	.tag .dot { width: 6px; height: 6px; border-radius: 999px; background: var(--sap-blue); }
131	.tag.yellow .dot { background: var(--sap-yellow); }
132	
133	/* ---------- Panels (Core Mechanism) ---------- */
134	.panel {
135	  background: var(--white); border: 1px solid var(--line);
136	  border-radius: var(--radius-lg); padding: 28px;
137	  box-shadow: var(--shadow-sm);
138	}
139	.panel h3 {
140	  margin: 0 0 10px; font-size: 19px; font-weight: 700;
141	  display: flex; align-items: center; gap: 10px;
142	}
143	.panel h3 .pill {
144	  font-size: 11px; font-weight: 700;
145	  padding: 3px 8px; border-radius: 999px;
146	  letter-spacing: .04em;
147	}
148	.panel.before h3 .pill { background: var(--danger-soft); color: var(--danger); }
149	.panel.after  h3 .pill { background: var(--sap-blue-soft); color: var(--sap-blue-deep); }
150	.panel.after { border-color: #BFDCFF; }
151	.panel p { color: var(--ink-2); margin: 0 0 14px; }
152	.panel ul { margin: 0; padding-left: 18px; color: var(--ink-2); }
153	.panel ul li { margin-bottom: 8px; }
154	.panel ul li::marker { color: var(--sap-blue); }
155	.panel.after ul li::marker { color: var(--sap-yellow); }
156	
157	/* ---------- Callout ---------- */
158	.callout {
159	  margin-top: 36px;
160	  background: linear-gradient(135deg, var(--sap-blue-soft) 0%, #FFF6D6 100%);
161	  border: 1px solid #D5E6FF;
162	  border-radius: var(--radius-lg);
163	  padding: 24px 28px;
164	  color: var(--ink);
165	}
166	
167	/* ---------- Chips ---------- */
168	.chip {
169	  padding: 6px 12px; border-radius: 999px;
170	  background: var(--sap-yellow-soft); color: #6E5200;
171	  border: 1px solid #F1D98A;
172	  font-weight: 700; font-size: 13px;
173	}
174	.chip.blue { background: var(--sap-blue-soft); color: var(--sap-blue-deep); border-color: #BFDCFF; }
175	
176	/* ---------- Subhead divider ---------- */
177	.subhead {
178	  display: flex; align-items: center; gap: 10px;
179	  margin: 32px 0 16px; font-size: 18px; font-weight: 700;
180	}
181	.subhead .ln { flex: 1; height: 1px; background: var(--line); }
182	
183	/* ---------- GIF slot (Phase B) ---------- */
184	.gif-slot {
185	  margin: 24px 0 0;
