(function initInstallBlock() {
  const block = document.querySelector('.install-block');
  if (!block) return;

  const tabs  = block.querySelectorAll('.install-tab');
  const panes = block.querySelectorAll('.install-pane');

  function activate(target) {
    tabs.forEach(t => {
      const on = t.dataset.target === target;
      t.classList.toggle('is-active', on);
      t.setAttribute('aria-selected', String(on));
    });
    panes.forEach(p => {
      const on = p.dataset.pane === target;
      p.classList.toggle('is-active', on);
      if (on) p.removeAttribute('hidden');
      else    p.setAttribute('hidden', '');
    });
  }

  tabs.forEach(t => {
    t.addEventListener('click', () => activate(t.dataset.target));
    t.addEventListener('keydown', (e) => {
      if (e.key !== 'ArrowDown' && e.key !== 'ArrowUp' &&
          e.key !== 'ArrowRight' && e.key !== 'ArrowLeft') return;
      e.preventDefault();
      const arr  = Array.from(tabs);
      const idx  = arr.indexOf(t);
      const next = (e.key === 'ArrowDown' || e.key === 'ArrowRight')
        ? arr[(idx + 1) % arr.length]
        : arr[(idx - 1 + arr.length) % arr.length];
      next.focus();
      activate(next.dataset.target);
    });
  });

  // Copy-to-clipboard — uses code[data-raw] (plain, untagged source)
  block.querySelectorAll('.install-copy').forEach(btn => {
    btn.addEventListener('click', async () => {
      const pane = btn.closest('.install-pane');
