/* ============================================================
   Install Block — vertical OS selector + adaptive code pane
   Light + dark themed via tokens.css.
   ============================================================ */
.install-block {
  display: grid;
  grid-template-columns: 168px 1fr;
  max-width: 760px;
  margin: 26px auto 32px;
  text-align: left;
  background: var(--white);
  border: 1px solid var(--line);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-md);
  overflow: hidden;
}

/* Left vertical tab list */
.install-tabs {
  display: flex;
  flex-direction: column;
  gap: 2px;
  padding: 10px;
  background: var(--bg);
  border-right: 1px solid var(--line);
}
.install-tab {
  display: flex; align-items: center; gap: 9px;
  padding: 9px 12px;
  border-radius: 10px;
  background: transparent;
  border: 1px solid transparent;
  color: var(--ink-3);
  font-family: 'Inter', 'Noto Sans KR', system-ui, sans-serif;
  font-size: 13.5px; font-weight: 600;
  cursor: pointer;
  text-align: left;
  transition: background .15s ease, color .15s ease, border-color .15s ease;
}
.install-tab svg { width: 15px; height: 15px; flex-shrink: 0; }
.install-tab:hover { color: var(--ink); background: var(--white); }
.install-tab.is-active {
  background: var(--white);
  color: var(--sap-blue);
  border-color: var(--line);
  box-shadow: 0 1px 2px rgba(11,27,51,.05);
}
.install-tab:focus-visible {
  outline: 2px solid var(--sap-blue);
  outline-offset: 2px;
}

/* Right code pane */
.install-panes { position: relative; min-width: 0; }
.install-pane[hidden] { display: none; }
.install-pane-bar {
  display: flex; align-items: center; justify-content: space-between;
  padding: 8px 12px 8px 16px;
  background: var(--white);
  border-bottom: 1px solid var(--line);
}
.install-pane-os {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 11.5px; font-weight: 600;
  color: var(--ink-3);
  letter-spacing: .04em;
}
.install-copy {
  display: inline-flex; align-items: center; gap: 6px;
  padding: 5px 10px;
  border-radius: 8px;
  border: 1px solid var(--line);
  background: var(--bg);
  color: var(--ink-2);
  font-size: 12px; font-weight: 600;
  cursor: pointer;
  transition: color .15s ease, background-color .15s ease, border-color .15s ease;
}
.install-copy svg { width: 12px; height: 12px; }
.install-copy:hover { color: var(--sap-blue); border-color: #BFDCFF; }
.install-copy.copied { color: var(--ok); border-color: rgba(14,143,98,.35); }
.install-copy:focus-visible {
  outline: 2px solid var(--sap-blue);
  outline-offset: 2px;
}

/* The actual code block — adapts to theme */
.install-code {
  margin: 0;
  padding: 16px 18px 18px;
  background: #F4F6FA;
  color: var(--ink);
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 13px;
  line-height: 1.7;
  white-space: pre;
  overflow-x: auto;
}
.install-code code { font: inherit; color: inherit; }
.install-code .cm { color: var(--ink-3); font-style: italic; }
.install-code .fn { color: var(--sap-blue); font-weight: 700; }
.install-code .sl { color: #B88900; font-weight: 700; }

/* Dark-theme adaptation */
[data-theme="dark"] .install-block {
  background: #0F1A30;
  border-color: #1F2A3E;
}
[data-theme="dark"] .install-tabs {
  background: #0B1425;
  border-right-color: #1F2A3E;
}
[data-theme="dark"] .install-tab { color: var(--ink-3); }
[data-theme="dark"] .install-tab:hover { color: var(--ink); background: #14233D; }
[data-theme="dark"] .install-tab.is-active {
  background: #14233D;
  color: #6FC0FF;
  border-color: #1F3357;
  box-shadow: 0 1px 2px rgba(0,0,0,.35);
}
[data-theme="dark"] .install-pane-bar {
  background: #0F1A30;
  border-bottom-color: #1F2A3E;
}
[data-theme="dark"] .install-copy {
  background: #14233D;
  border-color: #1F3357;
  color: var(--ink-2);
}
[data-theme="dark"] .install-copy:hover { color: #6FC0FF; border-color: #2A4A7C; }
[data-theme="dark"] .install-copy.copied { color: var(--ok); border-color: rgba(78,215,160,.4); }
[data-theme="dark"] .install-code {
  background: #071328;
  color: #E9EFF7;
}
[data-theme="dark"] .install-code .cm { color: #7B8DAB; }
[data-theme="dark"] .install-code .fn { color: #8ED1FF; }
[data-theme="dark"] .install-code .sl { color: var(--sap-yellow); }

/* Responsive — collapse vertical tabs into a horizontal scroll bar */
@media (max-width: 640px) {
  .install-block {
    grid-template-columns: 1fr;
  }
  .install-tabs {
    flex-direction: row;
    overflow-x: auto;
    border-right: none;
    border-bottom: 1px solid var(--line);
    padding: 8px;
    gap: 6px;
  }
  [data-theme="dark"] .install-tabs { border-bottom-color: #1F2A3E; }
  .install-tab { white-space: nowrap; padding: 8px 12px; }
  .install-code { font-size: 12.5px; padding: 14px 14px 16px; }
}

