file.content:
/* ---------- Hero — Core Capabilities 12 cards (Phase B) ---------- */
.cap-grid {
  display: grid; grid-template-columns: repeat(4, 1fr);
  gap: 14px; margin-top: 48px; text-align: left;
}
@media (max-width: 1020px) { .cap-grid { grid-template-columns: repeat(3, 1fr); } }
@media (max-width: 760px)  { .cap-grid { grid-template-columns: repeat(2, 1fr); } }
@media (max-width: 420px)  { .cap-grid { grid-template-columns: 1fr; } }
.cap-card {
  background: var(--white); border: 1px solid var(--line);
  border-radius: var(--radius-md); padding: 16px 16px 18px;
  transition: transform .15s ease, box-shadow .15s ease, border-color .15s;
  cursor: pointer;
  user-select: none;
}
.cap-card:hover {
  transform: translateY(-2px);
  box-shadow: var(--shadow-sm);
  border-color: #BFDCFF;
}
.cap-card:focus-visible {
  outline: 2px solid var(--sap-blue);
  outline-offset: 3px;
}
.cap-card.is-active {
  border-color: var(--sap-blue);
  box-shadow: 0 0 0 3px rgba(0, 112, 242, 0.18), var(--shadow-sm);
  transform: translateY(-2px);
}
.cap-card .cap-no {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px; font-weight: 700; color: var(--sap-blue);
  letter-spacing: .08em;
}
.cap-card .cap-icon { font-size: 22px; line-height: 1; margin: 6px 0 8px; }
.cap-card h4 { margin: 0 0 6px; font-size: 14px; font-weight: 700; color: var(--ink); }
.cap-card p  { margin: 0; font-size: 12.5px; color: var(--ink-2); line-height: 1.5; }

/* ---------- Section Layout ---------- */
section.block {
  padding: 84px 24px;
  border-top: 1px solid var(--line);
  background: var(--white);
}
section.block.alt { background: var(--bg); }
.section-inner { max-width: 1280px; margin: 0 auto; }
.section-head { max-width: 940px; margin: 0 0 40px; }
.section-kicker {
  display: inline-block;
  font-size: 13px; font-weight: 700; letter-spacing: .12em;

input.old_string:
.cap-card h4 { margin: 0 0 6px; font-size: 14px; font-weight: 700; color: var(--ink); }
.cap-card p  { margin: 0; font-size: 12.5px; color: var(--ink-2); line-height: 1.5; }

/* ---------- Section Layout ---------- */

input.new_string:
.cap-card h4 { margin: 0 0 6px; font-size: 14px; font-weight: 700; color: var(--ink); }
.cap-card p  { margin: 0; font-size: 12.5px; color: var(--ink-2); line-height: 1.5; }

/* ---------- Hero — Capability detail panel (replaces G1 GIF slot) ---------- */
.cap-detail {
  background: var(--white);
  border: 1px solid var(--line);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-sm);
  padding: 28px 32px;
  text-align: left;
  min-height: 240px;
}
.cap-detail-empty {
  display: grid; place-items: center;
  min-height: 220px;
  text-align: center;
  color: var(--ink-3);
}
.cap-detail-empty-icon {
  font-size: 32px; margin-bottom: 10px;
  animation: capBob 2s ease-in-out infinite;
}
.cap-detail-empty p { margin: 0; font-size: 14px; }
@keyframes capBob { 0%,100% { transform: translateY(0); } 50% { transform: translateY(4px); } }

.cap-detail-card { animation: capFade .22s ease; }
@keyframes capFade { from { opacity: 0; transform: translateY(4px); } to { opacity: 1; transform: none; } }

.cap-detail-head {
  display: flex; align-items: center; gap: 12px;
  margin-bottom: 6px;
  flex-wrap: wrap;
}
.cap-detail-no {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px; font-weight: 700;
  color: var(--sap-blue);
  background: var(--sap-blue-soft);
  padding: 4px 10px; border-radius: 999px;
  letter-spacing: .08em;
}
.cap-detail-icon { font-size: 26px; line-height: 1; }
.cap-detail-title {
  margin: 0; font-size: 22px; font-weight: 800;
  color: var(--ink); letter-spacing: -0.02em;
}
.cap-detail-cmd {
  margin-left: auto;
  font-family: 'JetBrains Mono', monospace;
  font-size: 12.5px; font-weight: 600;
  background: var(--sap-yellow-soft);
  color: #6E5200;
  border: 1px solid #F1D98A;
  padding: 4px 12px; border-radius: 8px;
  white-space: nowrap;
}
.cap-detail-subtitle {
  font-size: 13.5px; color: var(--sap-blue-deep);
  font-weight: 600;
  margin: 0 0 14px;
}
.cap-detail-desc {
  font-size: 14.5px; color: var(--ink-2);
  line-height: 1.65;
  margin: 0 0 18px;
}
.cap-detail-bullets {
  display: grid; grid-template-columns: repeat(2, 1fr);
  gap: 8px 28px;
  margin: 0; padding: 0; list-style: none;
}
@media (max-width: 720px) {
  .cap-detail-bullets { grid-template-columns: 1fr; }
  .cap-detail { padding: 20px 22px; }
}
.cap-detail-bullets li {
  font-size: 13px; color: var(--ink-2);
  padding-left: 20px;
  position: relative;
  line-height: 1.55;
}
.cap-detail-bullets li::before {
  content: '✓';
  position: absolute; left: 0; top: 0;
  color: var(--sap-blue);
  font-weight: 700;
}
.cap-detail-bullets li code {
  font-family: 'JetBrains Mono', monospace;
  font-size: .92em;
  color: var(--ink);
  background: var(--bg);
  padding: 1px 6px; border-radius: 4px;
}

/* ---------- Section Layout ---------- */
